// Loop through all incoming items safely in "Run Once for All Items" mode
return $input.all().map((item, index) => {

    // 1. Fetch exact paired original item directly using cross-node index parsing
    let originalData = {};
    try {
        // Targets the exact incoming loop run matched with this item index
        originalData = $('Loop Over Items').all()[index].json;
    } catch (e) {
        // Fallback safety layer to read from parent stream nodes
        try {
            originalData = $('Get row(s) in sheet').all()[index].json;
        } catch (err) {
            originalData = item.json;
        }
    }

    const aiRawOutput = item.json.output || "";

    // 2. Comprehensive Data Validation Check using resolved original source fields
    if (!originalData.profile_url || !originalData.id) {
        return {
            json: {
                id: originalData.id || `UNKNOWN-${index + 1}`,
                profile_url: originalData.profile_url || "",
                company_name: originalData.company_name || "N/A",
                headline: originalData.headline || "N/A",
                certification_level: "N/A",
                status: "failed",
                error_log: "Missing required profile fields from source sheet",
                processed_at: new Date().toISOString()
            },
            pairedItem: { index: index }
        };
    }

    // 3. Parse and extract category from AI Response safely
    let aiOutput = "Unknown";
    if (aiRawOutput) {
        let cleanText = aiRawOutput;

        // Extract inner values if AI returned a JSON string wrapper
        try {
            if (cleanText.includes('{')) {
                const parsed = JSON.parse(cleanText.substring(cleanText.indexOf('{'), cleanText.lastIndexOf('}') + 1));
                if (parsed.category) {
                    cleanText = parsed.category;
                } else if (parsed.certification_level) {
                    cleanText = parsed.certification_level;
                }
            }
        } catch (e) {
            // Keep original text format if parsing hits a dead end
        }

        const matchText = cleanText.toLowerCase();
        if (matchText.includes("gold")) aiOutput = "Gold";
        else if (matchText.includes("silver")) aiOutput = "Silver";
        else if (matchText.includes("authorized")) aiOutput = "Authorized";
        else if (matchText.includes("n/a") || matchText.includes("unknown")) aiOutput = "Unknown";
    }

    // 4. Construct Perfect Structured Output pairing unique items together 
    return {
        json: {
            id: originalData.id,
            profile_url: originalData.profile_url,
            company_name: originalData.company_name || "N/A",
            headline: originalData.headline || "N/A",
            certification_level: aiOutput,
            status: "processed",
            error_log: "None",
            processed_at: new Date().toISOString()
        },
        pairedItem: { index: index }
    };
});
